# pxcore/renderer/font.py — embedded 8x8 monospace bitmap font (printable ASCII).
#
# Source: font8x8_basic (Daniel Hepper, public domain; derived from the classic IBM PC BIOS
# 8x8 font). Embedded as a hex table so the core needs NO external font file and NO
# third-party dependency — a crisp, anti-alias-free bitmap is also exactly what a vision
# encoder reads most reliably (no grey edges to confabulate over).
#
# Encoding: each glyph is 8 bytes = 8 rows, top to bottom. Within a row, bit 0 (value 1) is
# the LEFTMOST pixel. A set bit = ink.
#
# This is a DATA module: it is deliberately swappable. The calibration battery's exact-string
# probe is what earns any font the right to be trusted for imaged reference content, so a
# glyph error degrades a fidelity score rather than silently corrupting output.
from __future__ import annotations

from typing import Dict, List, Tuple

