_MISSING = (0x00, 0x7E, 0x42, 0x42, 0x42, 0x42, 0x7E, 0x00)  # hollow box for unknowns


def glyph_rows(ch: str) -> Tuple[int, ...]:
    """8 row-bytes for a character. Unknown/non-printable → a visible box, never blank, so a
    coverage gap is *seen* rather than silently dropped."""
    return _GLYPHS.get(ord(ch) if ch else 0x20, _MISSING)


def glyph_bitmap(ch: str) -> List[List[int]]:
    """8x8 matrix of 0/1, row-major, [row][col] with col 0 = leftmost."""
    rows = glyph_rows(ch)
    return [[(row >> col) & 1 for col in range(CELL)] for row in rows]
